namespace Hdweb\Enquiry\Controller\Adminhtml\Items;

class Index extends \Hdweb\Enquiry\Controller\Adminhtml\Items
{
    /**
     * Items list.
     *
     * @return \Magento\Backend\Model\View\Result\Page
     */
    public function execute()
    {
        /** @var \Magento\Backend\Model\View\Result\Page $resultPage */
        $resultPage = $this->resultPageFactory->create();
        $resultPage->setActiveMenu('Hdweb_Enquiry::test');
        $resultPage->getConfig()->getTitle()->prepend(__('Enquiry Items'));
        $resultPage->addBreadcrumb(__('Enquiry'), __('Enquiry'));
        $resultPage->addBreadcrumb(__('Items'), __('Items'));
        return $resultPage;
    }
}